import{_ as a,o as e,c as t,ae as r}from"./chunks/framework.BzQXgbNp.js";const l="/assets/shop-create.C2BsJ0Q4.png",n="/assets/chest-shop.DO8zaa9x.png",u=JSON.parse('{"title":"🔨 如何建立遊戲內箱子商店","description":"","frontmatter":{},"headers":[],"relativePath":"Mc-Create-Shop.md","filePath":"Mc-Create-Shop.md"}'),s={name:"Mc-Create-Shop.md"};function i(c,o,d,h,p,g){return e(),t("div",null,[...o[0]||(o[0]=[r('<h1 id="🔨-如何建立遊戲內箱子商店" tabindex="-1">🔨 如何建立遊戲內箱子商店 <a class="header-anchor" href="#🔨-如何建立遊戲內箱子商店" aria-label="Permalink to &quot;🔨 如何建立遊戲內箱子商店&quot;">​</a></h1><p>本伺服器採用了全自訂的<strong>聊天欄互動式建立系統</strong>，您無需手動書寫複雜的告示牌內容，只需幾個簡單的步驟即可自動建立一個受保護的交易商店。</p><hr><h2 id="🏪-建立步驟" tabindex="-1">🏪 建立步驟 <a class="header-anchor" href="#🏪-建立步驟" aria-label="Permalink to &quot;🏪 建立步驟&quot;">​</a></h2><h3 id="_1-進入建立模式" tabindex="-1">1. 進入建立模式 <a class="header-anchor" href="#_1-進入建立模式" aria-label="Permalink to &quot;1. 進入建立模式&quot;">​</a></h3><p>在遊戲中輸入指令 <strong><code>/shop</code></strong> 開啟商店箱子選單。點擊下方的 <strong><code>§a[建立商店]</code></strong> 按鈕（Slot 49，綠色寶石標誌）。</p><ul><li>點擊後，系統會自動關閉選單，並在聊天欄顯示：<code>§b[Craft-Core] §a★ 商店建立模式 ★</code>。</li><li>您有 30 秒的有效建立時間。</li></ul><h3 id="_2-綁定箱子與商品" tabindex="-1">2. 綁定箱子與商品 <a class="header-anchor" href="#_2-綁定箱子與商品" aria-label="Permalink to &quot;2. 綁定箱子與商品&quot;">​</a></h3><ol><li>將您想要上架販售的物品**拿在主手（Main Hand）**上。</li><li>對著您要用來擺攤的**實體箱子（或木桶）**按 <strong>【左鍵】（即擊打方塊）</strong>。</li><li>綁定成功後，聊天欄會顯示：<code>§b[Craft-Core] §e【步驟 1/2】設定出售價格</code>。</li></ol><hr><h2 id="💬-3-聊天欄價格設定" tabindex="-1">💬 3. 聊天欄價格設定 <a class="header-anchor" href="#💬-3-聊天欄價格設定" aria-label="Permalink to &quot;💬 3. 聊天欄價格設定&quot;">​</a></h2><p>系統會引導您在聊天欄依序輸入價格：</p><h3 id="【步驟-1-2】設定出售價格-玩家買您商品的單價" tabindex="-1">【步驟 1/2】設定出售價格 (玩家買您商品的單價) <a class="header-anchor" href="#【步驟-1-2】設定出售價格-玩家買您商品的單價" aria-label="Permalink to &quot;【步驟 1/2】設定出售價格 (玩家買您商品的單價)&quot;">​</a></h3><ul><li>在聊天欄直接輸入正整數（如 <code>100</code>），即代表玩家花費 $100 可以買到 1 個該商品。</li><li>若您的商店<strong>不提供出售</strong>（純粹收購材料），請輸入 <strong><code>0</code></strong> 或 <strong><code>none</code></strong>。</li><li>輸入 <strong><code>取消</code></strong> 可以放棄建立商店。</li></ul><h3 id="【步驟-2-2】設定收購價格-您向玩家回收物品的單價" tabindex="-1">【步驟 2/2】設定收購價格 (您向玩家回收物品的單價) <a class="header-anchor" href="#【步驟-2-2】設定收購價格-您向玩家回收物品的單價" aria-label="Permalink to &quot;【步驟 2/2】設定收購價格 (您向玩家回收物品的單價)&quot;">​</a></h3><ul><li>在聊天欄直接輸入正整數（如 <code>50</code>），即代表玩家可以將手上相同的物品以 $50 賣給您（交易款項會從店主您的個人餘額中扣除）。</li><li>若您的商店<strong>不提供收購</strong>，請輸入 <strong><code>0</code></strong> 或 <strong><code>none</code></strong>。</li><li>輸入 <strong><code>取消</code></strong> 可以放棄建立商店。</li></ul><hr><h2 id="🎉-4-建立成功效果" tabindex="-1">🎉 4. 建立成功效果 <a class="header-anchor" href="#🎉-4-建立成功效果" aria-label="Permalink to &quot;🎉 4. 建立成功效果&quot;">​</a></h2><p>當兩個價格設定完畢且合法後：</p><ol><li>系統會自動在箱子上生成一個<strong>告示牌</strong>，並自動填寫好所有商店資訊（格式範例如下圖所示）。</li><li>箱子上方會出現 <strong>3D 懸浮的商品模型</strong>，方便其他玩家一眼辨識您的擺攤！</li><li>該箱子會自動被系統鎖定保護，防範 any 未經授權的玩家開啟或破壞。</li></ol><p><img src="'+l+'" alt="告示牌建立格式範例"></p><p><img src="'+n+'" alt="建立成功的箱子商店懸浮外觀"></p>',22)])])}const m=a(s,[["render",i]]);export{u as __pageData,m as default};
